import './Dropdown.scss';

import type { NewDropdownMenuProps } from ':components/NewDropdownMenu';
import { NewDropdownMenu } from ':components/NewDropdownMenu';
import type { FC } from 'react';
import React, { useCallback } from 'react';

import { classNames } from '../../helpers/classnames';
import type { DropdownProps } from './Dropdown.types';

export const Dropdown: FC<DropdownProps> = ({
	anchorRef,
	open,
	onOpen,
	onClose,
	onOutsideClick,
	placement = 'bottom-start',
	verticalOffset = 1,
	horizontalOffset = 0,
	widthMode = 'widthParent',
	shouldRenderOverlay,
	overlayClassName,
	overlayScroll,
	scrollable,
	minHeight,
	applicationRootElementID,
	dropdownElementID,
	className,
	children,
	dataTestId = 'Dropdown',
}) => {
	const handleSetOpen = useCallback(
		(nextOpen: boolean) => {
			if (nextOpen) {
				onOpen?.();
			} else {
				onClose?.();
			}
		},
		[onOpen, onClose],
	);

	if (!open) {
		return null;
	}

	const menuProps: NewDropdownMenuProps = {
		targetElement: anchorRef,
		isOpen: open,
		handleSetOpen,
		align: placement,
		verticalOffset,
		horizontalOffset,
		widthMode,
		shouldRenderOverlay,
		overlayClassName,
		overlayScroll,
		scrollable,
		minHeight,
		applicationRootElementID,
		dropdownElementID,
		onOutsideClick,
		dataTestId,
		className: classNames('dsb_dropdown', className),
	};

	return <NewDropdownMenu {...menuProps}>{children}</NewDropdownMenu>;
};
